function generateMonthlyExpenseEvent(char){
  if(char.age < 16) return null;
  // Pick 4 distinct items, each with its own rolled cost
  const pool = MONTHLY_EXPENSES.slice();
  const picks = [];
  const count = Math.min(4, pool.length);
  for(let i=0; i<count; i++){
    const idx = ri(0, pool.length-1);
    const item = pool.splice(idx, 1)[0];
    picks.push({item, cost: ri(item.min, item.max)});
  }
  const descLines = picks.map(p => `${p.item.icon} ${p.item.name} â€” ${fmt$(p.cost)}`).join('  Â·  ');
  const choices = [];
  for(const p of picks){
    choices.push({
      text:`Buy ${p.item.icon} ${p.item.name} â€” ${fmt$(p.cost)}`,
      fn(c){
        c.checking -= p.cost;
        const bump = ri(1,3);
        c.creditScore = clamp(c.creditScore + bump, 300, 850);
        if(!c.belongings) c.belongings=[];
        c.belongings.push({id:`b_${Date.now()}_${Math.random().toString(36).slice(2,7)}`, name:p.item.name, icon:p.item.icon, cost:p.cost, purchasedAt:c.monthAge});
        return `Paid ${fmt$(p.cost)} for ${p.item.name}. Added to belongings â€” sell anytime from Assets tab. Credit score +${bump}.`;
      }
    });
  }
  for(const p of picks){
    choices.push({
      text:`Defer ${p.item.icon} ${p.item.name} â€” ${fmt$(p.cost)} (10 mo)`,
      fn(c){
        if(!c.pendingExpenses) c.pendingExpenses=[];
        c.pendingExpenses.push({name:p.item.name, icon:p.item.icon, cost:p.cost, monthsLeft:10});
        return `Deferred ${p.item.name}. ${fmt$(p.cost)} due in 10 months. Miss it and your credit takes a hit.`;
      }
    });
  }
  choices.push({
    text:`Pass â€” none of these`,
    fn(){ return `Skipped this month's offers. Maybe next time.`; }
  });
  return {
    id: 'monthly_expense_'+Date.now(),
    title: 'Monthly Shopping Offers',
    cat: 'expense',
    icon: picks[0].item.icon,
    desc: `Four items caught your eye this month. Pick one to buy, defer the cost up to 10 months, or pass entirely.\n\n${descLines}`,
    choices,
  };
}

tool_input.content:
// Quick smoke check â€” load page, start game, age ~24 months, ensure no console/page errors.
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const ctx = await browser.newContext({ viewport: { width: 1280, height: 800 } });
  const page = await ctx.newPage();
  const errs = [];
  page.on('console', m => { if (m.type() === 'error') errs.push('console: ' + m.text()); });
  page.on('pageerror', e => errs.push('page: ' + e.message));
  await page.goto('http://localhost:3000/bitlife-finance.html', { waitUntil: 'domcontentloaded' });
  await page.evaluate(() => { try { localStorage.removeItem('finlife_save'); } catch(e){} });
  await page.reload({ waitUntil: 'domcontentloaded' });
  await page.waitForSelector('#screen-new.active', { timeout: 5000 });
  await page.fill('#inp-name', 'Smoke');
  await page.click('#btn-start');
  await page.waitForSelector('#screen-game.active', { timeout: 5000 });
  for (let i = 0; i < 60; i++) {
    // auto-dismiss modals so we can keep aging
    for (let k = 0; k < 8; k++) {
      const open = await page.$('#modal-overlay.open');
      if (!open) break;
      const btns = await page.$$('#m-choices button');
      let idx = -1;
      for (let j = 0; j < btns.length; j++) {
        const t = (await btns[j].textContent() || '').toLowerCase();
        if (/pass|close|cancel|skip|continue|back/.test(t)) { idx = j; break; }
      }
      if (idx < 0) idx = Math.max(0, btns.length - 1);
      if (btns[idx]) await btns[idx].click({ force: true }).catch(()=>{});
      await page.waitForTimeout(30);
    }
    await page.click('#btn-age', { force: true }).catch(()=>{});
    await page.waitForTimeout(40);
  }
  const seenExpenseOffer = await page.evaluate(() => {
    return (GS.inbox||[]).length;
  });
  console.log(JSON.stringify({ errors: errs, inbox: seenExpenseOffer }, null, 2));
  await browser.close();
})().catch(e => { console.error('FATAL', e); process.exit(1); });

